import{_ as a,p as s,q as e,a1 as n}from"./framework-5866ffd3.js";const d={},i=n(`<h1 id="htpasswd" tabindex="-1"><a class="header-anchor" href="#htpasswd" aria-hidden="true">#</a> htpasswd</h1><p>apache服务器创建密码认证文件</p><h2 id="补充说明" tabindex="-1"><a class="header-anchor" href="#补充说明" aria-hidden="true">#</a> 补充说明</h2><p><strong>htpasswd命令</strong> 是Apache的Web服务器内置工具，用于创建和更新储存用户名、域和用户基本认证的密码文件。</p><h3 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h3><h3 id="htpasswd-选项-参数" tabindex="-1"><a class="header-anchor" href="#htpasswd-选项-参数" aria-hidden="true">#</a> htpasswd(选项)(参数)</h3><h3 id="选项" tabindex="-1"><a class="header-anchor" href="#选项" aria-hidden="true">#</a> 选项</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>-c：创建一个加密文件；
-n：不更新加密文件，只将加密后的用户名密码显示在屏幕上；
-m：默认采用MD5算法对密码进行加密；
-d：采用CRYPT算法对密码进行加密；
-p：不对密码进行进行加密，即明文密码；
-s：采用SHA算法对密码进行加密；
-b：在命令行中一并输入用户名和密码而不是根据提示输入密码；
-D：删除指定的用户。
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h3><ul><li>用户：要创建或者更新密码的用户名；</li><li>密码：用户的新密码。</li></ul><h3 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h3><p><strong>利用htpasswd命令添加用户</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>htpasswd <span class="token parameter variable">-bc</span> .passwd www.jsdig.com php
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在bin目录下生成一个.passwd文件，用户名www.jsdig.com，密码：php，默认采用MD5加密方式。</p><p><strong>在原有密码文件中增加下一个用户</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>htpasswd <span class="token parameter variable">-b</span> .passwd Jack <span class="token number">123456</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>去掉<code>-c</code>选项，即可在第一个用户之后添加第二个用户，依此类推。</p><p><strong>不更新密码文件，只显示加密后的用户名和密码</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>htpasswd <span class="token parameter variable">-nb</span> Jack <span class="token number">123456</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>不更新.passwd文件，只在屏幕上输出用户名和经过加密后的密码。</p><p><strong>利用htpasswd命令删除用户名和密码</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>htpasswd <span class="token parameter variable">-D</span> .passwd Jack
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>利用htpasswd命令修改密码</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>htpasswd <span class="token parameter variable">-D</span> .passwd Jack
htpasswd <span class="token parameter variable">-b</span> .passwd Jack <span class="token number">123456</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>即先使用htpasswd删除命令删除指定用户，再利用htpasswd添加用户命令创建用户即可实现修改密码的功能。</p>`,25),r=[i];function l(t,c){return s(),e("div",null,r)}const h=a(d,[["render",l],["__file","htpasswd.html.vue"]]);export{h as default};
